# Database setup
Base = declarative_base()

# Association table for many-to-many relationship between products and categories
product_categories = Table(
    'product_categories',
    Base.metadata,
    Column('product_id', Integer, ForeignKey('products.id'), primary_key=True),
    Column('category_id', Integer, ForeignKey('categories.id'), primary_key=True),
)


# SQLAlchemy Models
class SellerModel(Base):
    __tablename__ = 'sellers'

    id = Column(Integer, primary_key=True, autoincrement=True)
    name = Column(String(255), nullable=False)
    email = Column(String(255), nullable=False, unique=True)
    rating = Column(Float, default=0.0)

    products = relationship("ProductModel", back_populates="seller")


class CategoryModel(Base):
    __tablename__ = 'categories'

    id = Column(Integer, primary_key=True, autoincrement=True)
    name = Column(String(255), nullable=False, unique=True)
    description = Column(Text, nullable=True)
    parent_id = Column(Integer, ForeignKey('categories.id'), nullable=True)

    parent = relationship("CategoryModel", remote_side=[id], back_populates="subcategories")
    subcategories = relationship("CategoryModel", back_populates="parent")
    products = relationship("ProductModel", secondary=product_categories, back_populates="categories")


class ProductModel(Base):
    __tablename__ = 'products'

    id = Column(Integer, primary_key=True, autoincrement=True)
    name = Column(String(255), nullable=False)
    description = Column(Text, nullable=True)
    price = Column(Float, nullable=False)
    stock = Column(Integer, default=0)
    seller_id = Column(Integer, ForeignKey('sellers.id'), nullable=False)

    seller = relationship("SellerModel", back_populates="products")
    reviews = relationship("ReviewModel", back_populates="product")
    images = relationship("ImageModel", back_populates="product")
    categories = relationship("CategoryModel", secondary=product_categories, back_populates="products")


class ReviewModel(Base):
    __tablename__ = 'reviews'

    id = Column(Integer, primary_key=True, autoincrement=True)
    product_id = Column(Integer, ForeignKey('products.id'), nullable=False)
    reviewer_name = Column(String(255), nullable=False)
    rating = Column(Integer, nullable=False)
    comment = Column(Text, nullable=True)

    product = relationship("ProductModel", back_populates="reviews")


class ImageModel(Base):
    __tablename__ = 'images'

    id = Column(Integer, primary_key=True, autoincrement=True)
    product_id = Column(Integer, ForeignKey('products.id'), nullable=False)
    url = Column(String(512), nullable=False)
    alt_text = Column(String(255), nullable=True)
    is_primary = Column(Integer, default=0)  # Using Integer for SQLite compatibility

    product = relationship("ProductModel", back_populates="images")


# Database engine and session
engine = create_engine("sqlite:///products.db", echo=False)
Base.metadata.create_all(engine)
SessionLocal = sessionmaker(bind=engine)


@contextmanager
def get_session():
    session = SessionLocal()
    try:
        yield session
    finally:
        session.close()


